# Django: teclado es frontend. Servimos HTML con keydown.
from django.http import HttpResponse

def keys(request):
    return HttpResponse('''
      <div id="box" tabindex="0" style="padding:16px;border:1px solid #ccc;">Presiona Ctrl+S / Escape</div>
      <script>
        const box = document.getElementById("box");
        box.addEventListener("keydown", (e) => {
          if (e.ctrlKey && e.key.toLowerCase()==="s") { e.preventDefault(); console.log("Ctrl+S"); }
          if (e.key==="Escape") console.log("Escape");
        });
        box.focus();
      </script>
    ''')

